#include "valve_proportional.h"
#include <Arduino.h>
#define VALVE_PIN 25
static uint8_t _opening=0;
void valve_setup(){ledcAttach(VALVE_PIN,1000,8);Serial.println("[valve] OK");}
void valve_set_opening(uint8_t p){_opening=constrain(p,0,100);ledcWrite(VALVE_PIN,map(_opening,0,100,0,255));}
uint8_t valve_get_opening(){return _opening;}
void valve_close(){valve_set_opening(0);}
void valve_full_open(){valve_set_opening(100);}
